import{_ as t,c as o,o as a,aj as i}from"./chunks/framework.BlveriQe.js";const u=JSON.parse('{"title":"Interface: InvitationEvent","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/InvitationEvent.md","filePath":"reference/js-bao-wss-client/api/interfaces/InvitationEvent.md"}'),n={name:"reference/js-bao-wss-client/api/interfaces/InvitationEvent.md"};function r(c,e,d,s,l,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / InvitationEvent</p><h1 id="interface-invitationevent" tabindex="-1">Interface: InvitationEvent <a class="header-anchor" href="#interface-invitationevent" aria-label="Permalink to “Interface: InvitationEvent”">​</a></h1><p>Real-time notification that a document invitation has changed state.</p><p>Emitted over the <code>invitation</code> event channel (<code>client.on(&quot;invitation&quot;, ...)</code>).</p><p><strong>Important:</strong> events are targeted — most actions are delivered to only one side of the invitation (inviter <em>or</em> invitee, not both). Consumers must write a switch that handles every action value, or they will silently drop events. See <a href="#action">InvitationEvent.action</a> for the full list and who receives each.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="acceptedby" tabindex="-1">acceptedBy? <a class="header-anchor" href="#acceptedby" aria-label="Permalink to “acceptedBy?”">​</a></h3><blockquote><p><code>optional</code> <strong>acceptedBy?</strong>: <code>string</code></p></blockquote><p>UserId of the invitee who accepted. Populated only when <code>action === &quot;accepted&quot;</code>.</p><hr><h3 id="action" tabindex="-1">action <a class="header-anchor" href="#action" aria-label="Permalink to “action”">​</a></h3><blockquote><p><strong>action</strong>: <code>&quot;created&quot;</code> | <code>&quot;updated&quot;</code> | <code>&quot;cancelled&quot;</code> | <code>&quot;declined&quot;</code> | <code>&quot;accepted&quot;</code></p></blockquote><p>The lifecycle transition that just occurred for this invitation.</p><p><strong>Targeting (who receives each action — note the asymmetry):</strong></p><ul><li><code>&quot;created&quot;</code> — sent to the <strong>invitee only</strong>. A new invitation has been sent to them; their UI should surface it.</li><li><code>&quot;updated&quot;</code> — sent to the <strong>invitee only</strong>. An existing pending invitation was changed (e.g. permission re-issued / expiry extended).</li><li><code>&quot;cancelled&quot;</code> — sent to the <strong>invitee only</strong>. The inviter (or an admin) cancelled the pending invitation; the invitee&#39;s UI should drop it from their pending list.</li><li><code>&quot;declined&quot;</code> — sent to <strong>both the invitee and the inviter</strong>. The invitee explicitly declined; both sides&#39; UIs should update (invitee removes from pending, inviter sees the outcome).</li><li><code>&quot;accepted&quot;</code> — sent to the <strong>inviter only</strong>. The invitee accepted and now holds a <code>DocumentPermission</code>; the inviter&#39;s UI can update collaborator lists. <code>acceptedBy</code> carries the accepting user&#39;s <code>userId</code>.</li></ul><p>New action values may be added in the future (non-breaking); consumer switches should include a <code>default</code> branch that is either a no-op or a warning rather than throwing.</p><hr><h3 id="document" tabindex="-1">document? <a class="header-anchor" href="#document" aria-label="Permalink to “document?”">​</a></h3><blockquote><p><code>optional</code> <strong>document?</strong>: <code>object</code></p></blockquote><h4 id="createdat" tabindex="-1">createdAt? <a class="header-anchor" href="#createdat" aria-label="Permalink to “createdAt?”">​</a></h4><blockquote><p><code>optional</code> <strong>createdAt?</strong>: <code>string</code></p></blockquote><h4 id="createdby" tabindex="-1">createdBy? <a class="header-anchor" href="#createdby" aria-label="Permalink to “createdBy?”">​</a></h4><blockquote><p><code>optional</code> <strong>createdBy?</strong>: <code>string</code></p></blockquote><h4 id="documentid" tabindex="-1">documentId? <a class="header-anchor" href="#documentid" aria-label="Permalink to “documentId?”">​</a></h4><blockquote><p><code>optional</code> <strong>documentId?</strong>: <code>string</code></p></blockquote><h4 id="lastmodified" tabindex="-1">lastModified? <a class="header-anchor" href="#lastmodified" aria-label="Permalink to “lastModified?”">​</a></h4><blockquote><p><code>optional</code> <strong>lastModified?</strong>: <code>string</code></p></blockquote><h4 id="tags" tabindex="-1">tags? <a class="header-anchor" href="#tags" aria-label="Permalink to “tags?”">​</a></h4><blockquote><p><code>optional</code> <strong>tags?</strong>: <code>string</code>[]</p></blockquote><h4 id="title" tabindex="-1">title? <a class="header-anchor" href="#title" aria-label="Permalink to “title?”">​</a></h4><blockquote><p><code>optional</code> <strong>title?</strong>: <code>string</code></p></blockquote><hr><h3 id="documentid-1" tabindex="-1">documentId <a class="header-anchor" href="#documentid-1" aria-label="Permalink to “documentId”">​</a></h3><blockquote><p><strong>documentId</strong>: <code>string</code></p></blockquote><hr><h3 id="expiresat" tabindex="-1">expiresAt? <a class="header-anchor" href="#expiresat" aria-label="Permalink to “expiresAt?”">​</a></h3><blockquote><p><code>optional</code> <strong>expiresAt?</strong>: <code>string</code></p></blockquote><hr><h3 id="invitationid" tabindex="-1">invitationId <a class="header-anchor" href="#invitationid" aria-label="Permalink to “invitationId”">​</a></h3><blockquote><p><strong>invitationId</strong>: <code>string</code></p></blockquote><hr><h3 id="invitedat" tabindex="-1">invitedAt? <a class="header-anchor" href="#invitedat" aria-label="Permalink to “invitedAt?”">​</a></h3><blockquote><p><code>optional</code> <strong>invitedAt?</strong>: <code>string</code></p></blockquote><hr><h3 id="invitedby" tabindex="-1">invitedBy? <a class="header-anchor" href="#invitedby" aria-label="Permalink to “invitedBy?”">​</a></h3><blockquote><p><code>optional</code> <strong>invitedBy?</strong>: <code>string</code></p></blockquote><hr><h3 id="permission" tabindex="-1">permission <a class="header-anchor" href="#permission" aria-label="Permalink to “permission”">​</a></h3><blockquote><p><strong>permission</strong>: <code>string</code></p></blockquote><hr><h3 id="title-1" tabindex="-1">title? <a class="header-anchor" href="#title-1" aria-label="Permalink to “title?”">​</a></h3><blockquote><p><code>optional</code> <strong>title?</strong>: <code>string</code></p></blockquote><hr><h3 id="type" tabindex="-1">type <a class="header-anchor" href="#type" aria-label="Permalink to “type”">​</a></h3><blockquote><p><strong>type</strong>: <code>&quot;invitation&quot;</code></p></blockquote>',57)])])}const b=t(n,[["render",r]]);export{u as __pageData,b as default};
